import{_ as t,c as a,o as r,ag as i}from"./chunks/framework.Dj4VfQLU.js";const h=JSON.parse('{"title":"What is BetterTaxi?","description":"","frontmatter":{"icon":"bolt-lightning"},"headers":[],"relativePath":"README.md","filePath":"README.md"}'),s={name:"README.md"};function o(n,e,l,d,c,p){return r(),a("div",null,e[0]||(e[0]=[i('<h1 id="what-is-bettertaxi" tabindex="-1">What is BetterTaxi? <a class="header-anchor" href="#what-is-bettertaxi" aria-label="Permalink to &quot;What is BetterTaxi?&quot;">​</a></h1><p><strong>BetterTaxi</strong> is a robust white-label <strong>ride-hailing and parcel delivery solution</strong> built to serve a wide spectrum of users—from solo developers and tech startups to established transportation and logistics firms. Designed with adaptability and quality in mind, BetterTaxi provides a seamless multi-platform experience that minimizes operational costs while maximizing scalability and performance.</p><p>At its core, BetterTaxi is about giving businesses <strong>real choice</strong>. It comes with flexible support for over <strong>22 payment gateways</strong>, <strong>8 SMS providers</strong>, and <strong>5 map service options</strong>, allowing deployments that suit local markets and budgets without vendor lock-in. Whether you’re launching a local ride-share platform or a nationwide parcel service, BetterTaxi empowers you with the tools to build and scale confidently.</p><p>The system supports <strong>modular extensions</strong>, such as a <strong>Partnership Add-on</strong> for enabling shared revenue models, and tight integration with <strong>BetterShop</strong>, making it a powerful backbone for hybrid ride-and-delivery operations.</p><p>On the technical front, BetterTaxi leverages <strong>real-time WebSocket-based tracking</strong>, <strong>GraphQL APIs</strong> for type-safe, backend-heavy integrations, and <strong>Docker-based deployment</strong> for simple, containerized scaling. This makes it especially well-suited to rapid development cycles and enterprise-grade infrastructure, such as that used across the BetterSuite ecosystem.</p><p>With a focus on <strong>design excellence</strong>, <strong>extensibility</strong>, and <strong>developer-friendliness</strong>, BetterTaxi stands out in a crowded market by delivering unmatched quality, flexibility, and real-world utility.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>We recommend using online documentation for the most up-to-date information. You can find it at <a href="https://docs.bettersuite.io/bettertaxi/" target="_blank" rel="noreferrer">BetterTaxi Documentation</a>.</p></div>',7)]))}const m=t(s,[["render",o]]);export{h as __pageData,m as default};
